import { describe, expect, it } from 'vitest';

import {
  adist,
  admitProximityEdge,
  consistentTriangle,
  genuineEdge,
  nonTrivial,
  reciprocal,
  reciprocityResidual,
  spoofEdge,
  triangleConsistent,
  triangleConsistentTri,
  trivialClaim,
  UltrasonicProximityMaster,
  violatingTriangle,
  zeroEdge,
  type ProximityClaim,
} from '../src/ultrasonic-proximity';

describe('adist (mirrors adist_self / adist_comm)', () => {
  it('is zero at a point with itself', () => {
    for (const a of [0, 1, 5, 42]) {
      expect(adist(a, a)).toBe(0);
    }
  });

  it('is the absolute difference and symmetric', () => {
    expect(adist(12, 13)).toBe(1);
    expect(adist(13, 12)).toBe(1);
    expect(adist(12, 30)).toBe(18);
  });

  it('saturates at zero (Nat truncated subtraction)', () => {
    expect(adist(0, 0)).toBe(0);
    expect(Math.max(0, 4 - 9)).toBe(0);
  });
});

describe('reciprocity gate (mirrors reciprocityResidual / reciprocalB)', () => {
  it('measures the asymmetry of the two directional ToFs', () => {
    expect(reciprocityResidual(genuineEdge)).toBe(1);
    expect(reciprocityResidual(spoofEdge)).toBe(18);
    expect(reciprocityResidual(zeroEdge)).toBe(0);
  });

  it('a symmetric round trip clears reciprocity at any tolerance', () => {
    // mirrors equal_directions_reciprocal
    const sym: ProximityClaim = { aToB: 7, bToA: 7, claimedDist: 7 };
    expect(reciprocal(0, sym)).toBe(true);
    expect(reciprocal(5, sym)).toBe(true);
  });

  it('the genuine edge is reciprocal, the spoof beacon is not', () => {
    expect(reciprocal(2, genuineEdge)).toBe(true);
    expect(reciprocal(2, spoofEdge)).toBe(false);
  });
});

describe('support / non-triviality gate (mirrors trivialClaimB / nonTrivialB)', () => {
  it('an all-zero claim is trivial (no ranging)', () => {
    expect(trivialClaim(zeroEdge)).toBe(true);
    expect(nonTrivial(zeroEdge)).toBe(false);
  });

  it('a claim with a positive ToF carries support', () => {
    // mirrors positive_aToB_nonTrivial
    expect(nonTrivial(genuineEdge)).toBe(true);
    expect(nonTrivial(spoofEdge)).toBe(true);
    expect(nonTrivial({ aToB: 1, bToA: 0, claimedDist: 1 })).toBe(true);
  });
});

describe('triangle consistency (mirrors triangleConsistentB)', () => {
  it('admits when the direct hop is within the around-the-corner path + tol', () => {
    // 8 <= 5 + 4 + 1 = 10
    expect(triangleConsistent(8, 5, 4, 1)).toBe(true);
    expect(triangleConsistentTri(1, consistentTriangle)).toBe(true);
  });

  it('rejects an inflated direct hop (third-ear hard negative)', () => {
    // 20 <= 5 + 4 + 1 = 10 is false
    expect(triangleConsistent(20, 5, 4, 1)).toBe(false);
    expect(triangleConsistentTri(1, violatingTriangle)).toBe(false);
  });

  it('honors the metric triangle inequality at zero slack on true distances', () => {
    // mirrors true_distances_triangle_consistent: adist a c <= adist a b + adist b c
    for (const [a, b, c] of [
      [0, 5, 9],
      [3, 3, 3],
      [10, 1, 4],
    ]) {
      expect(triangleConsistent(adist(a, c), adist(a, b), adist(b, c), 0)).toBe(
        true,
      );
    }
  });
});

describe('promotion check: admitProximityEdge', () => {
  it('admits a reciprocal, non-trivial edge', () => {
    // mirrors genuine_edge_admitted
    const a = admitProximityEdge(genuineEdge, { tol: 2 });
    expect(a.outcome).toBe('claim_admitted');
    expect(a.reciprocal).toBe(true);
    expect(a.nonTrivial).toBe(true);
    expect(a.reciprocityResidual).toBe(1);
    expect(a.limitation).toBe('none');
  });

  it('reports but does not promote a non-reciprocal spoof beacon', () => {
    // mirrors spoof_rejected
    const a = admitProximityEdge(spoofEdge, { tol: 2 });
    expect(a.outcome).toBe('observation_only');
    expect(a.limitation).toBe('non_reciprocal_spoof');
    expect(a.reciprocal).toBe(false);
    expect(a.nonTrivial).toBe(true);
    expect(a.reciprocityResidual).toBe(18);
  });

  it('withholds a zero-ToF claim (no ranging happened)', () => {
    // mirrors zero_tof_rejected: reciprocal but trivial
    const a = admitProximityEdge(zeroEdge, { tol: 2 });
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('no_ranging');
    expect(a.reciprocal).toBe(true);
    expect(a.nonTrivial).toBe(false);
  });

  it('same forward ToF, opposite verdicts (forward range is not an edge key)', () => {
    // mirrors same_forward_tof_opposite_verdict
    expect(genuineEdge.aToB).toBe(spoofEdge.aToB);
    expect(admitProximityEdge(genuineEdge, { tol: 2 }).outcome).toBe(
      'claim_admitted',
    );
    expect(admitProximityEdge(spoofEdge, { tol: 2 }).outcome).not.toBe(
      'claim_admitted',
    );
  });
});

describe('UltrasonicProximityMaster (mirrors ultrasonic_proximity_master)', () => {
  it('every boundary witness holds', () => {
    expect(UltrasonicProximityMaster.genuineEdgeAdmitted).toBe(true);
    expect(UltrasonicProximityMaster.spoofNotReciprocal).toBe(true);
    expect(UltrasonicProximityMaster.spoofRejected).toBe(true);
    expect(UltrasonicProximityMaster.zeroReciprocal).toBe(true);
    expect(UltrasonicProximityMaster.zeroRejected).toBe(true);
    expect(UltrasonicProximityMaster.triangleConsistent).toBe(true);
    expect(UltrasonicProximityMaster.triangleViolationRejected).toBe(true);
    expect(UltrasonicProximityMaster.sameForwardTofOppositeVerdict).toBe(true);
  });
});
